mapper.select:
/* selectWmi10SKUList */
select A.COMPKEY as compkey , A.WAREKEY as warekey , A.OWNERKY as ownerky , A.SKUMKEY as skumkey , C.SKUDESC as skudesc , A.STKSTAT as stkstat , C.UPCCODE as upccode , SUM(A.STOTQTY) as stotqty , SUM( case when (A.STOTQTY != 0 and A.SALLQTY = 0 and A.SINBQTY = 0 and A.SOUBQTY = 0) then A.STOTQTY - A.SBLOQTY else 0 end) as avalqty , SUM(A.SALLQTY) as sallqty , SUM(A.SINBQTY) as sinbqty , SUM(A.SOUBQTY) as soubqty , SUM(A.SBLOQTY) as sbloqty , ( SELECT SUM(STOTQTY) FROM WSTKKY WHERE COMPKEY = A.COMPKEY AND WAREKEY = A.WAREKEY AND OWNERKY = A.OWNERKY AND SKUMKEY = A.SKUMKEY AND AREAKEY = 'RCV' AND (A.STOTQTY != 0 OR A.SALLQTY != 0 OR A.SINBQTY != 0 OR A.SOUBQTY != 0 OR A.SBLOQTY != 0) ) AS rcvsqty ,( SELECT SUM(STOTQTY) FROM WSTKKY WHERE COMPKEY = A.COMPKEY AND WAREKEY = A.WAREKEY AND OWNERKY = A.OWNERKY AND SKUMKEY = A.SKUMKEY AND AREAKEY = 'STG' AND (A.STOTQTY != 0 OR A.SALLQTY != 0 OR A.SINBQTY != 0 OR A.SOUBQTY != 0 OR A.SBLOQTY != 0) ) AS stgsqty , ( SELECT SUM(STOTQTY) FROM WSTKKY WHERE COMPKEY = A.COMPKEY AND WAREKEY = A.WAREKEY AND OWNERKY = A.OWNERKY AND SKUMKEY = A.SKUMKEY AND AREAKEY = 'TAK' AND (A.STOTQTY != 0 OR A.SALLQTY != 0 OR A.SINBQTY != 0 OR A.SOUBQTY != 0 OR A.SBLOQTY != 0) ) AS taksqty from WSTKKY A inner join MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY left outer join SUSRMA E on A.COMPKEY = E.COMPKEY and C.SKUAT01 = E.USERACT inner join(SELECT COMPKEY, WAREKEY, AREAKEY, ZONEKEY, LOCAKEY, LOCANAM FROM MLOCMA) ML on A.COMPKEY = ML.COMPKEY and A.WAREKEY = ML.WAREKEY and A.AREAKEY = ML.AREAKEY and A.ZONEKEY = ML.ZONEKEY and A.LOCAKEY = ML.LOCAKEY where 1=1 and A.COMPKEY = #{userData.compkey} and (A.STOTQTY != 0 or A.SALLQTY != 0 or A.SINBQTY != 0 or A.SOUBQTY != 0 or A.SBLOQTY != 0)
and A.OWNERKY = #{ownerky}
and A.WAREKEY = #{warekey}
and A.AREAKEY not in ('SYS', 'SHP')
and A.AREAKEY = #{areakey}
and A.ZONEKEY = #{zonekey}
and ML.LOCANAM like concat( '%' , #{locanam} , '%')
and A.SKUMKEY like concat( '%' , #{skumkey} , '%')
and C.SKUDESC like concat( '%' , #{skudesc} , '%')
and A.STKSTAT = #{stkstat}
and C.UPCCODE like concat( '%' , #{upccode} , '%')
group by A.COMPKEY, A.OWNERKY, A.WAREKEY, A.SKUMKEY, C.SKUDESC, A.STKSTAT, C.UPCCODE, RCVSQTY, STGSQTY, TAKSQTY

/* selectWmi10LOCAList */
select A.COMPKEY as compkey , A.WAREKEY as warekey , A.OWNERKY as ownerky , A.SKUMKEY as skumkey , C.SKUDESC as skudesc , A.STKSTAT as stkstat , C.UPCCODE as upccode , A.AREAKEY as areakey , A.ZONEKEY as zonekey , A.LOCAKEY as locakey , MA.AREANAM as areanam , MZ.ZONENAM as zonenam , ML.LOCANAM as locanam , SUM(A.STOTQTY) as stotqty , SUM( case when (A.STOTQTY != 0 and A.SALLQTY = 0 and A.SINBQTY = 0 and A.SOUBQTY = 0) then A.STOTQTY - A.SBLOQTY else 0 end) as avalqty , SUM(A.SALLQTY) as sallqty , SUM(A.SINBQTY) as sinbqty , SUM(A.SOUBQTY) as soubqty , SUM(A.SBLOQTY) as sbloqty from WSTKKY A inner join MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY left outer join SUSRMA E on A.COMPKEY = E.COMPKEY and C.SKUAT01 = E.USERACT inner join(SELECT COMPKEY, WAREKEY, AREAKEY, AREANAM FROM MAREMA) MA on A.COMPKEY = MA.COMPKEY and A.WAREKEY = MA.WAREKEY and A.AREAKEY = MA.AREAKEY inner join(SELECT COMPKEY, WAREKEY, AREAKEY, ZONEKEY, ZONENAM FROM MZONMA) MZ on A.COMPKEY = MZ.COMPKEY and A.WAREKEY = MZ.WAREKEY and A.AREAKEY = MZ.AREAKEY and A.ZONEKEY = MZ.ZONEKEY inner join(SELECT COMPKEY, WAREKEY, AREAKEY, ZONEKEY, LOCAKEY, LOCANAM FROM MLOCMA) ML on A.COMPKEY = ML.COMPKEY and A.WAREKEY = ML.WAREKEY and A.AREAKEY = ML.AREAKEY and A.ZONEKEY = ML.ZONEKEY and A.LOCAKEY = ML.LOCAKEY where 1=1 and A.COMPKEY = #{userData.compkey} and (A.STOTQTY != 0 or A.SALLQTY != 0 or A.SINBQTY != 0 or A.SOUBQTY != 0 or A.SBLOQTY != 0)
and A.OWNERKY = #{ownerky}
and A.WAREKEY = #{warekey}
and A.AREAKEY not in ('SYS', 'SHP')
and A.AREAKEY = #{areakey}
and A.ZONEKEY = #{zonekey}
and ML.LOCANAM like concat( '%' , #{locanam} , '%')
and A.SKUMKEY like concat( '%' , #{skumkey} , '%')
and C.SKUDESC like concat( '%' , #{skudesc} , '%')
and A.STKSTAT = #{stkstat}
and C.UPCCODE like concat( '%' , #{upccode} , '%')
group by A.COMPKEY, A.OWNERKY, A.WAREKEY, A.SKUMKEY, C.SKUDESC, A.STKSTAT, C.UPCCODE, A.AREAKEY, A.ZONEKEY , A.LOCAKEY, MA.AREANAM, MZ.ZONENAM, ML.LOCANAM

/* selectWmi10LOTList */
select A.COMPKEY as compkey , A.OWNERKY as ownerky , A.SKUMKEY as skumkey , C.SKUDESC as skudesc , A.WAREKEY as warekey , A.AREAKEY as areakey , A.ZONEKEY as zonekey , A.LOCAKEY as locakey , SUM(A.STOTQTY) as stotqty , SUM( case when (A.STOTQTY != 0 and A.SALLQTY = 0 and A.SINBQTY = 0 and A.SOUBQTY = 0) then A.STOTQTY - A.SBLOQTY else 0 end) as avalqty , SUM(A.SALLQTY) as sallqty , SUM(A.SINBQTY) as sinbqty , SUM(A.SOUBQTY) as soubqty , SUM(A.SBLOQTY) as sbloqty , A.STKSTAT as stkstat , A.LOTAT01 as lotat01 , A.LOTAT02 as lotat02 , A.LOTAT03 as lotat03 , A.LOTAT04 as lotat04 , A.LOTAT05 as lotat05 , A.LOTAT06 as lotat06 , A.LOTAT07 as lotat07 , A.LOTAT08 as lotat08 , A.LOTAT09 as lotat09 , A.LOTAT10 as lotat10 , A.LOTAT11 as lotat11 , A.LOTAT12 as lotat12 , A.LOTAT13 as lotat13 , A.LOTAT14 as lotat14 , A.LOTAT15 as lotat15 , A.LOTAT16 as lotat16 , A.LOTAT17 as lotat17 , A.LOTAT18 as lotat18 , A.LOTAT19 as lotat19 , A.LOTAT20 as lotat20 , A.LOTNMKY as lotnmky , MA.AREANAM as areanam , MZ.ZONENAM as zonenam , ML.LOCANAM as locanam , C.UPCCODE as upccode , A.SHELIFE as shelife , fn_com_todate(A.EXPIDAT) as expidat from WSTKKY A inner join MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY left outer join SUSRMA E on A.COMPKEY = E.COMPKEY and C.SKUAT01 = E.USERACT inner join(SELECT COMPKEY, WAREKEY, AREAKEY, AREANAM FROM MAREMA) MA on A.COMPKEY = MA.COMPKEY and A.WAREKEY = MA.WAREKEY and A.AREAKEY = MA.AREAKEY inner join(SELECT COMPKEY, WAREKEY, AREAKEY, ZONEKEY, ZONENAM FROM MZONMA) MZ on A.COMPKEY = MZ.COMPKEY and A.WAREKEY = MZ.WAREKEY and A.AREAKEY = MZ.AREAKEY and A.ZONEKEY = MZ.ZONEKEY inner join(SELECT COMPKEY, WAREKEY, AREAKEY, ZONEKEY, LOCAKEY, LOCANAM FROM MLOCMA) ML on A.COMPKEY = ML.COMPKEY and A.WAREKEY = ML.WAREKEY and A.AREAKEY = ML.AREAKEY and A.ZONEKEY = ML.ZONEKEY and A.LOCAKEY = ML.LOCAKEY where 1=1 and A.COMPKEY = #{userData.compkey} and (A.STOTQTY != 0 or A.SALLQTY != 0 or A.SINBQTY != 0 or A.SOUBQTY != 0 or A.SBLOQTY != 0)
and A.OWNERKY = #{ownerky}
and A.WAREKEY = #{warekey}
and A.AREAKEY not in ('SYS', 'SHP')
and A.AREAKEY = #{areakey}
and A.ZONEKEY = #{zonekey}
and ML.LOCANAM like concat( '%' , #{locanam} , '%')
and A.SKUMKEY like concat( '%' , #{skumkey} , '%')
and C.SKUDESC like concat( '%' , #{skudesc} , '%')
and A.STKSTAT = #{stkstat}
and C.UPCCODE like concat( '%' , #{upccode} , '%')
group by A.COMPKEY, A.OWNERKY, A.WAREKEY, A.SKUMKEY, C.SKUDESC, A.LOTNMKY, A.AREAKEY, A.ZONEKEY, A.LOCAKEY, A.STKSTAT, A.SHELIFE, COALESCE(A.EXPIDAT, ' '), A.LOTAT01, A.LOTAT02, A.LOTAT03, A.LOTAT04, A.LOTAT05, A.LOTAT06, A.LOTAT07, A.LOTAT08, A.LOTAT09, A.LOTAT10, A.LOTAT11, A.LOTAT12, A.LOTAT13, A.LOTAT14, A.LOTAT15, A.LOTAT16, A.LOTAT17, A.LOTAT18, A.LOTAT19, A.LOTAT20, MA.AREANAM, MZ.ZONENAM, ML.LOCANAM, C.UPCCODE

/* selectWmi12WstkkyList */ select concat(A.COMPKEY , A.STOCKKY) as rowkey , A.COMPKEY as compkey , ' ' as adjsoky , A.WAREKEY as warekey , '600' as doccate , '620' as doctype , 'BEFORE' as adjmode , ' ' as adjgrky , ' ' as rsncode , ' ' as adjsrmk , A.STKSTAT as stkstat, L.LOCANAM as locanam , A.STOCKKY as stockky , A.AREAKEY as areakey , A.ZONEKEY as zonekey , A.LOCAKEY as locakey , A.SUBSECT as subsect , A.TRUNTYP as truntyp , A.TRUNPID as trunpid , A.LOTNMKY as lotnmky , A.OWNERKY as ownerky , A.SKUMKEY as skumkey , C.SKUDESC as skudesc , A.SIRBCOD as sirbcod , A.STOTQTY as stotqty , A.SALLQTY as sallqty , A.SINBQTY as sinbqty , A.SOUBQTY as soubqty , A.SBLOQTY as sbloqty , 0 as schnqty , A.SUOMKEY as suomkey , date_format(A.PRODDAT , '%Y-%m-%d') as proddat , A.SHELIFE as shelife , fn_com_todate(A.EXPIDAT) as expidat , date_format(A.RCVDCDT , '%Y-%m-%d') as rcvdcdt , date_format(A.RCVFRDT, '%Y-%m-%d') as rcvfrdt , A.LOTFRKY as lotfrky , A.BLOCKID as blockid , A.PHYSROW as physrow , A.PHYSSEC as physsec , A.PHYSFLO as physflo , A.RCVDCKY as rcvdcky , A.RCVDCIT as rcvdcit , A.TASKOKY as taskoky , A.TASKOIT as taskoit , A.SHPDCKY as shpdcky , A.SHPDCIT as shpdcit , A.PHYSOKY as physoky , A.PHYSOIT as physoit , A.STORFKY as storfky , fn_com_todate(A.CREDATE) as credate , fn_com_totime(A.CRETIME) as cretime , fn_sy_usernam(A.COMPKEY , A.CREUSER) as creuser , fn_com_todate(A.LMODATE) as lmodate , fn_com_totime(A.LMOTIME) as lmotime , fn_sy_usernam(A.COMPKEY , A.LMOUSER) as lmouser , ' ' as indibzl , ' ' as indiarc , 0 as updtchk from WSTKKY A inner join MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY inner join MLOCMA L on A.COMPKEY = L.COMPKEY and A.WAREKEY = L.WAREKEY and A.AREAKEY = L.AREAKEY and A.ZONEKEY = L.ZONEKEY and A.LOCAKEY = L.LOCAKEY
and A.COMPKEY = #{userData.compkey} and A.STOTQTY != 0 and A.SALLQTY = 0 and A.SINBQTY = 0 and A.SOUBQTY = 0 and A.AREAKEY = 'STG'
and A.OWNERKY = #{ownerky}
and A.WAREKEY = #{warekey}
and L.LOCANAM like concat( '%' , #{locanam} , '%')
and A.SKUMKEY like concat( '%' , #{skumkey} , '%')
and C.SKUDESC like concat( '%' , #{skudesc} , '%')
and A.STKSTAT = #{stkstat}
and A.STOCKKY = #{stockky}
order by A.STOCKKY, A.AREAKEY , A.ZONEKEY, A.LOCAKEY , A.SKUMKEY , C.SKUDESC

/* selectWmi12BeforeData */ select concat(A.COMPKEY , A.STOCKKY) as rowkey , A.COMPKEY as compkey , ' ' as adjsoky , A.WAREKEY as warekey , '600' as doccate , '630' as doctype , 'BEFORE' as adjmode , ' ' as adjgrky , ' ' as rsncode , ' ' as adjsrmk , A.STOCKKY as stockky, A.VENDKEY as vendkey, A.AREAKEY as areakey , A.ZONEKEY as zonekey , A.LOCAKEY as locakey , A.LOTNMKY as lotnmky , A.OWNERKY as ownerky , A.SKUMKEY as skumkey , C.SKUDESC as skudesc , A.STOTQTY as stotqty , A.SALLQTY as sallqty , A.SINBQTY as sinbqty , A.SOUBQTY as soubqty , A.SBLOQTY as sbloqty , 0 as schnqty , A.SUOMKEY as suomkey , A.LOTFRKY as lotfrky , A.STKSTAT as stkstat , A.RCVDCDT as rcvdcdt, A.BLOCKID as blockid , A.STORFKY as storfky , fn_com_todate(A.CREDATE) as credate , fn_com_totime(A.CRETIME) as cretime , fn_sy_usernam(A.COMPKEY , A.CREUSER) as creuser , fn_com_todate(A.LMODATE) as lmodate , fn_com_totime(A.LMOTIME) as lmotime , fn_sy_usernam(A.COMPKEY , A.LMOUSER) as lmouser , ' ' as indibzl , ' ' as indiarc , 0 as updtchk from WSTKKY A inner join MOWRMA B on A.COMPKEY = B.COMPKEY and A.OWNERKY = B.OWNERKY inner join MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY inner join MWARMA D on A.COMPKEY = D.COMPKEY and A.WAREKEY = D.WAREKEY
and A.COMPKEY = #{userData.compkey}
and A.STOTQTY = 0
and A.STOTQTY != 0
and A.SALLQTY = 0 and A.SINBQTY = 0 and A.SOUBQTY = 0 and A.AREAKEY = 'STG' and A.STOCKKY = #{stockky}

mapper.insert:
/* saveWmi12WadjitBeforeList */

insert into WADJIT
(
COMPKEY , ADJSOKY, ADJSOIT
, WAREKEY , DOCCATE , DOCTYPE
, ADJMODE , ADJGRKY , RSNCODE , ADJSRMK
, STOCKKY , AREAKEY , ZONEKEY , LOCAKEY
, SUBSECT , TRUNTYP , TRUNPID , LOTNMKY , OWNERKY
, SKUMKEY , SKUDESC
, VENDKEY , SIRBCOD
, STOTQTY , SALLQTY , SINBQTY , SOUBQTY , SBLOQTY
, SUOMKEY , PRODDAT , SHELIFE
, EXPIDAT , RCVDCDT , RCVFRDT , LOTFRKY
, STKSTAT , BLOCKID , PHYSROW , PHYSSEC , PHYSFLO
, RCVDCKY , RCVDCIT , TASKOKY, TASKOIT , SHPDCKY , SHPDCIT
, PHYSOKY , PHYSOIT , STORFKY
, CREDATE , CRETIME , CREUSER
, LMODATE , LMOTIME , LMOUSER
)
values(
#{userData.compkey} , #{adjsoky} , fn_wm_adjsoit(#{compkey} , #{adjsoky})
, #{warekey} , #{doccate} , #{doctype}
, "BEFORE", #{adjgrky} , #{rsncode} , #{adjsrmk}
, #{stockky} , #{areakey} , #{zonekey} , #{locakey}
, #{subsect} , #{truntyp} , #{trunpid} , #{lotnmky} , #{ownerky}
, #{skumkey} , #{skudesc}
, #{vendkey} , #{sirbcod}
, #{stotqty} , #{sallqty} , #{sinbqty} , #{soubqty} , #{sbloqty}
, #{suomkey} , replace(#{proddat}, '-', '') , #{shelife}
, replace(#{expidat}, '-', '') , replace(#{rcvdcdt}, '-', '') ,
replace(#{rcvfrdt}, '-', '') , #{lotnmky}
, #{stkstat} , #{blockid} , #{physrow} , #{physsec}, #{physflo}
, #{rcvdcky} , #{rcvdcit} , #{taskoky} , #{taskoit}, #{shpdcky} ,
#{shpdcit}
, #{physoky} , #{physoit} , #{storfky}
, to_char(now() , 'YYYYMMDD') , to_char(now(), 'hh24miss') ,
#{userData.useract}
, to_char(now() , 'YYYYMMDD') , to_char(now(), 'hh24miss') ,
#{userData.useract}
)

/* saveWmi12WadjitAfterList */

insert into WADJIT
(
COMPKEY , ADJSOKY, ADJSOIT
, WAREKEY , DOCCATE , DOCTYPE
, ADJMODE , ADJGRKY , RSNCODE , ADJSRMK
, STOCKKY , AREAKEY , ZONEKEY , LOCAKEY
, SUBSECT , TRUNTYP , TRUNPID , LOTNMKY , OWNERKY
