)

mapper.select:
/* selectWmi20WstkkyList */ select concat(A.COMPKEY , A.STOCKKY) as rowkey , A.COMPKEY as compkey , A.WAREKEY as warekey , '600' as doccate , '630' as doctype , A.STOCKKY as stockky , A.AREAKEY as areakey , A.ZONEKEY as zonekey , A.LOCAKEY as locakey , ML.LOCANAM as locanam , A.SBLOQTY as sbloqty , A.LOTNMKY as lotnmky , A.OWNERKY as ownerky , A.SKUMKEY as skumkey , C.SKUDESC as skudesc , A.STOTQTY as stotqty , A.STKSTAT as stkstat , A.SUOMKEY as suomkey , fn_com_todate(A.EXPIDAT) as EXPIDAT , fn_com_todate(A.CREDATE) as credate , fn_com_totime(A.CRETIME) as cretime , fn_sy_usernam(A.COMPKEY , A.CREUSER) as creuser , fn_com_todate(A.LMODATE) as lmodate , fn_com_totime(A.LMOTIME) as lmotime , fn_sy_usernam(A.COMPKEY , A.LMOUSER) as lmouser , ' ' as indibzl , ' ' as indiarc , 0 as updtchk from WSTKKY A inner join MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY left outer join SUSRMA U on U.COMPKEY = A.COMPKEY and U.USERACT = C.SKUAT01 inner join MLOCMA ML on ML.COMPKEY = A.COMPKEY and ML.WAREKEY = A.WAREKEY and ML.LOCAKEY = A.LOCAKEY where 1=1 and A.STOTQTY != 0 and A.SALLQTY = 0 and A.SINBQTY = 0 and A.SOUBQTY = 0 and A.AREAKEY = 'STG' and A.COMPKEY = #{userData.compkey}
and A.OWNERKY = #{ownerky}
and A.WAREKEY = #{warekey}
and ML.LOCANAM like concat('%' , #{locanam} , '%')
and A.SKUMKEY like concat('%' , #{skumkey} , '%')
and C.SKUDESC like concat('%' , #{skudesc} , '%')
and A.STKSTAT = #{stkstat}
order by A.WAREKEY , A.AREAKEY , A.ZONEKEY , A.LOCAKEY , A.SKUMKEY , C.SKUDESC , A.COMPKEY , A.OWNERKY

/* getPhysoky */
select
fn_wm_physoky() from dual

/* selectWmi21HeaderList */ select concat(A.COMPKEY , A.PHYSOKY) as rowkey , A.COMPKEY as compkey , A.PHYSOKY as physoky , A.WAREKEY as warekey , A.DOCCATE as doccate , A.DOCTYPE as doctype , A.PHYNAME as phyname , A.PHYMODE as phymode , A.OWNERKY as ownerky , fn_com_todate(A.CREDATE) as credate , fn_sy_usernam(A.COMPKEY , A.CREUSER) as creuser , fn_com_todate(A.LMODATE) as lmodate , fn_sy_usernam(A.COMPKEY , A.LMOUSER) as lmouser from WPHYIT A inner join MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY left outer join SUSRMA U on U.COMPKEY = A.COMPKEY and U.USERACT = C.SKUAT01 where 1=1 and A.COMPKEY = #{userData.compkey} and A.AREAKEY = 'STG' and A.PHYMODE in ('READY', 'WORKING')
and A.WAREKEY = #{warekey}
and A.OWNERKY = #{ownerky}
and A.SKUMKEY like concat('%' , #{skumkey} , '%')
and A.SKUDESC like concat('%' , #{skudesc} , '%')
and A.SKUMKEY = #{slctsku}
and A.PHYSOKY like concat('%' , #{physoky} , '%')
group by A.COMPKEY , A.PHYSOKY , A.WAREKEY , A.DOCCATE , A.DOCTYPE , A.PHYNAME , A.PHYMODE , A.OWNERKY order by A.PHYSOKY , A.PHYSOIT , A.WAREKEY , A.AREAKEY , A.ZONEKEY, A.LOCAKEY , A.SKUMKEY , C.SKUDESC , A.COMPKEY , A.OWNERKY

