/* selectWmi32List */ select concat(OE.COMPKEY , OE.OEADJKY) as rowkey, OE.COMPKEY AS compkey, OE.OEADJKY AS oeadjky, WJ.ADJSOKY AS adjsoky, OE.OEADJIT AS oeadjit, WJ.ADJSOIT AS adjsoit, WJ.ADJGRKY AS adjgrky, OE.WAREKEY AS warekey, OE.OWNERKY AS ownerky, CASE WHEN OE.DOCCATE = '300' THEN '600' END AS doccate, CASE WHEN OE.DOCTYPE = '310' THEN '610' WHEN OE.DOCTYPE = '320' THEN '620' END AS doctype, OE.STOCKKY AS stockky, fn_com_todate(WS.EXPIDAT) as EXPIDAT, OE.OEINSST AS oeinsst, WS.AREAKEY AS areakey, WS.ZONEKEY AS zonekey, WS.LOCAKEY AS locakey, WS.SKUMKEY AS skumkey, WS.SKUDESC AS skudesc, WS.STOTQTY AS stotqty, WS.SALLQTY as sallqty, WS.SINBQTY as sinbqty, WS.SOUBQTY as soubqty, WS.SBLOQTY as sbloqty, OE.RTODQTY AS rtodqty, OE.RTCFQTY AS rtcfqty, OE.RSNCODE AS rsncode, OE.ADJSRMK AS adjsrmk, OE.ATKSTAT AS atkstat, fn_com_todate(OE.CREDATE) as credate , fn_com_totime(OE.CRETIME) as cretime , fn_sy_usernam(OE.COMPKEY , OE.CREUSER) as creuser, fn_com_todate(OE.LMODATE) as lmodate , fn_com_totime(OE.LMOTIME) as lmotime , fn_sy_usernam(OE.COMPKEY , OE.LMOUSER) as lmouser, OE.INDIBZL as indibzl , OE.INDIARC as indiarc , OE.UPDTCHK as updtchk from OEADJI OE inner join (select ADJSOKY, ADJSOIT, ADJGRKY, COMPKEY, WAREKEY, OWNERKY, SKUMKEY, STOCKKY, OEADJKY, OEADJIT from WADJIT where COMPKEY = #{userData.compkey} and DOCCATE = '600' and DOCTYPE IN('610', '620') group by COMPKEY, WAREKEY, OWNERKY, STOCKKY, SKUMKEY, ADJSOKY, ADJGRKY, OEADJKY, OEADJIT) WJ on WJ.COMPKEY = OE.COMPKEY and WJ.WAREKEY = OE.WAREKEY and WJ.OWNERKY = OE.OWNERKY and WJ.SKUMKEY = OE.SKUMKEY and WJ.OEADJKY = OE.OEADJKY and WJ.OEADJIT = OE.OEADJIT left outer join (select COMPKEY, WAREKEY, OWNERKY, STOCKKY, SKUMKEY, LOTNMKY ,AREAKEY, ZONEKEY, LOCAKEY, SKUDESC, EXPIDAT, STKSTAT ,SUM(STOTQTY) AS STOTQTY ,SUM(SALLQTY) AS SALLQTY ,SUM(SINBQTY) as SINBQTY ,SUM(SOUBQTY) AS SOUBQTY ,SUM(SBLOQTY) AS SBLOQTY from WSTKKY where COMPKEY = #{userData.compkey} and WAREKEY = #{warekey} group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY, LOTNMKY, AREAKEY, ZONEKEY, LOCAKEY, SKUDESC, EXPIDAT, STKSTAT) WS on WS.COMPKEY = OE.COMPKEY and WS.OWNERKY = OE.OWNERKY and WS.WAREKEY = OE.WAREKEY and WS.SKUMKEY = OE.SKUMKEY and WS.AREAKEY = OE.AREAKEY and WS.ZONEKEY = OE.ZONEKEY and WS.LOCAKEY = OE.LOCAKEY and WS.LOTNMKY = OE.LOTNMKY and WS.STOCKKY = OE.STOCKKY where OE.COMPKEY = #{userData.compkey} and OE.OEINSST = 'NEW'
